#define SPI_HAL_H

#include <stdint.h>

typedef enum {
    SPI_MODE_0 = 0,
    SPI_MODE_1 = 1,
    SPI_MODE_2 = 2,
    SPI_MODE_3 = 3
} spi_mode_t;

typedef struct {
    uint32_t    clock_hz;
    spi_mode_t  mode;
    uint8_t     bits_per_word;
